export function getChapter2Quest(questId: number): ScenarioData | null {
  return CHAPTER_2_QUESTS.find(q => q.questId === questId) || null
}

export function getChapter2BossQuests(): ScenarioData[] {
  return CHAPTER_2_QUESTS.filter(q => q.isBoss)
}
